import { useRef, useState, useEffect } from "react";
import {
  motion,
  useMotionValue,
  useSpring,
  useTransform,
} from "framer-motion";
import "./ControlSlider.css";

function ControlSlider({
  label = "System Control",
  min = 0,
  max = 100,
  step = 5,
  value,
  defaultValue = 50,
  onChange,
  dangerThreshold = 80,
  unit = "",
}) {
  const trackRef = useRef(null);
  const isControlled = value !== undefined;
  const [internalValue, setInternalValue] = useState(defaultValue);

  const currentValue = isControlled ? value : internalValue;

  const rawX = useMotionValue(0);
  const springX = useSpring(rawX, { stiffness: 250, damping: 25 });

  // 🔥 FIX: useTransform instead of .to()
  const widthTransform = useTransform(springX, (v) => `${v}%`);
  const leftTransform = useTransform(springX, (v) => `${v}%`);

  const percentage = ((currentValue - min) / (max - min)) * 100;

  useEffect(() => {
    rawX.set(percentage);
  }, [percentage]);

  const snapToStep = (val) => {
    const snapped = Math.round(val / step) * step;
    return Math.max(min, Math.min(max, snapped));
  };

  const updateFromClientX = (clientX) => {
    const rect = trackRef.current.getBoundingClientRect();
    let percent = (clientX - rect.left) / rect.width;
    percent = Math.max(0, Math.min(1, percent));

    const valueFromPercent = min + percent * (max - min);
    const snappedValue = snapToStep(valueFromPercent);

    const snappedPercent =
      ((snappedValue - min) / (max - min)) * 100;

    rawX.set(snappedPercent);

    if (isControlled) {
      onChange && onChange(snappedValue);
    } else {
      setInternalValue(snappedValue);
      onChange && onChange(snappedValue);
    }
  };

  const handleMouseDown = (e) => {
    updateFromClientX(e.clientX);

    const move = (e) => updateFromClientX(e.clientX);
    const up = () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", up);
    };

    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", up);
  };

  const danger = currentValue >= dangerThreshold;

  return (
    <div className="glass-slider">
      <div className="slider-header">
        <span className="slider-label">{label}</span>
        <span className={`slider-value ${danger ? "danger" : ""}`}>
          {currentValue}{unit}
        </span>
      </div>

      <div
        ref={trackRef}
        className="slider-track"
        onMouseDown={handleMouseDown}
      >
        {/* Fill */}
        <motion.div
          className={`slider-fill ${danger ? "danger" : ""}`}
          style={{ width: widthTransform }}
        >
          <div className="energy-pulse" />
        </motion.div>

        {/* Handle */}
        <motion.div
          className={`slider-handle ${danger ? "danger" : ""}`}
          style={{ left: leftTransform }}
        />
      </div>
    </div>
  );
}

export default ControlSlider;

.glass-slider {
  width: 360px;
  padding: 20px;
  border-radius: 16px;
  background: rgba(20, 25, 30, 0.6);
  backdrop-filter: blur(14px);
  box-shadow:
    inset 0 0 0 1px rgba(255,255,255,0.06),
    0 20px 50px rgba(0,0,0,0.6);
  color: #d0d6db;
  font-family: sans-serif;
}

/* Header */
.slider-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 16px;
}

.slider-label {
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
  opacity: 0.6;
}

.slider-value {
  font-weight: 600;
  color: #5ef0b3;
  transition: color 0.3s ease;
}

.slider-value.danger {
  color: #ff5c5c;
}

/* Track */
.slider-track {
  position: relative;
  height: 12px;
  border-radius: 999px;
  background: rgba(255,255,255,0.05);
  backdrop-filter: blur(8px);
  overflow: hidden;
  cursor: pointer;
  box-shadow:
    inset 0 4px 10px rgba(0,0,0,0.6),
    inset 0 -1px 1px rgba(255,255,255,0.05);
}

/* Fill */
.slider-fill {
  position: absolute;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(
    90deg,
    #3bf0a4,
    #1fbf88
  );
  overflow: hidden;
  box-shadow: 0 0 12px rgba(59,240,164,0.5);
}

.slider-fill.danger {
  background: linear-gradient(
    90deg,
    #ff7a5c,
    #ff3c3c
  );
  box-shadow: 0 0 14px rgba(255,60,60,0.6);
}

/* Energy Pulse */
.energy-pulse {
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    90deg,
    rgba(255,255,255,0.15) 0px,
    rgba(255,255,255,0.15) 2px,
    transparent 2px,
    transparent 10px
  );
  animation: pulseMove 2s linear infinite;
  opacity: 0.3;
}

@keyframes pulseMove {
  from { transform: translateX(0); }
  to { transform: translateX(40px); }
}

/* Handle */
.slider-handle {
  position: absolute;
  top: 50%;
  transform: translate(-50%, -50%);
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, #ffffff, #c9d1d8);
  box-shadow:
    0 6px 15px rgba(0,0,0,0.7),
    inset 0 3px 6px rgba(255,255,255,0.4);
}

.slider-handle.danger {
  background: radial-gradient(circle at 30% 30%, #ffb3b3, #ff3c3c);
}
